/// <summary>
/// Represents a task or action item within a project.
/// </summary>
[Description("Represents a task or action item within a project.")]
public record Todo
{
    [Key]
    [Description("Unique identifier for the task")]
    public string Id { get; init; } = string.Empty;

    [Required]
    [Description("Short title describing the task")]
    public string Title { get; init; } = string.Empty;

    [Description("Detailed description of what needs to be done")]
    public string? Description { get; init; }

    [Description("Category for grouping related tasks")]
    public string Category { get; init; } = "General";

    [Description("Priority level of the task")]
    public TaskPriority Priority { get; init; } = TaskPriority.Medium;

    [Description("Person responsible for completing the task")]
    public string? Assignee { get; init; }

    [Description("Deadline for task completion")]
    public DateTimeOffset? DueDate { get; init; }

    [Description("Current status of the task")]
    public TodoStatus Status { get; init; } = TodoStatus.Pending;

    [Description("Icon name for visual representation")]
    public string Icon { get; init; } = "TaskListSquare";

    [Description("Timestamp when the task was created")]
    public DateTimeOffset CreatedAt { get; init; } = DateTimeOffset.UtcNow;

    [Description("Timestamp when the task was completed")]
    public DateTimeOffset? CompletedAt { get; init; }
}

[Description("Task completion status")]
public enum TodoStatus
{
    [Description("Task is waiting to be started")]
    Pending,
    [Description("Task is actively being worked on")]
    InProgress,
    [Description("Task is awaiting review")]
    InReview,
    [Description("Task has been completed")]
    Completed,
    [Description("Task is blocked by dependencies")]
    Blocked
}

[Description("Task priority level")]
public enum TaskPriority
{
    [Description("Low priority - can be done later")]
    Low,
    [Description("Medium priority - normal workflow")]
    Medium,
    [Description("High priority - should be done soon")]
    High,
    [Description("Critical priority - requires immediate attention")]
    Critical
}
